let score = 0;
let done = new Set();
let listeningIndex = 0;

const $ = (selector, root = document) => root.querySelector(selector);
const $$ = (selector, root = document) => Array.from(root.querySelectorAll(selector));

function escapeHtml(text) {
  return String(text ?? "").replace(/[&<>"]/g, (char) => ({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;"}[char]));
}

function safeText(text) {
  return String(text ?? "").replace(/\s+/g, " ").trim();
}

function speak(text) {
  if (!("speechSynthesis" in window)) {
    alert("Audio is not available in this browser.");
    return;
  }
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(safeText(text));
  const accent = $("#accent");
  utterance.lang = accent ? accent.value : "en-GB";
  utterance.rate = 0.9;
  window.speechSynthesis.speak(utterance);
}

window.speak = speak;

function addScore(id) {
  if (!done.has(id)) {
    done.add(id);
    score += 1;
    const scoreEl = $("#score");
    if (scoreEl) scoreEl.textContent = score;
  }
}

function setMax() {
  const max = DATA.grammarQuiz.length + DATA.sortQuiz.length + Math.min(DATA.numbers.length, 12) + DATA.listenings.length;
  const maxEl = $("#maxScore");
  if (maxEl) maxEl.textContent = max;
}

function renderDays() {
  $("#daysGrid").innerHTML = DATA.days.map((day) => `
    <article class="day-card">
      <h3>${escapeHtml(day[0])}</h3>
      <p class="fr">${escapeHtml(day[1])}</p>
      <p><strong>${escapeHtml(day[2])}</strong></p>
      <p>${escapeHtml(day[3])}</p>
      <button type="button" class="speak-btn" data-speak="${escapeHtml(day[0])}">🔊 Listen</button>
    </article>`).join("");
}

function renderMonths() {
  $("#monthsGrid").innerHTML = DATA.months.map((month) => `
    <div class="mini">
      <strong>${escapeHtml(month[0])}</strong><br>
      <span class="fr">${escapeHtml(month[1])}</span><br>
      <button type="button" class="speak-btn" data-speak="${escapeHtml(month[0])}">🔊</button>
    </div>`).join("");
}

function renderTime() {
  $("#timeGrid").innerHTML = DATA.timeExpressions.map((item) => `
    <article class="time-card">
      <span class="tag">${escapeHtml(item[0])}</span>
      <h3>${escapeHtml(item[1])}</h3>
      <p class="fr">${escapeHtml(item[2])}</p>
      <p>${escapeHtml(item[3])}</p>
      <button type="button" class="speak-btn" data-speak="${escapeHtml(item[1])}">🔊</button>
    </article>`).join("");
}

function makeQuiz(containerSelector, items, prefix) {
  const container = $(containerSelector);
  container.innerHTML = items.map((q, index) => `
    <div class="quiz-item">
      <p>${escapeHtml(q[0])}</p>
      <div class="options">
        ${q[2].map((option) => `<button type="button" data-answer="${escapeHtml(q[1])}" data-choice="${escapeHtml(option)}" data-id="${prefix}${index}">${escapeHtml(option)}</button>`).join("")}
      </div>
      <div class="feedback" aria-live="polite"></div>
    </div>`).join("");

  $$(`${containerSelector} button[data-choice]`).forEach((button) => {
    button.addEventListener("click", () => {
      const feedback = button.closest(".quiz-item").querySelector(".feedback");
      const itemIndex = Number(button.dataset.id.replace(prefix, ""));
      if (button.dataset.choice === button.dataset.answer) {
        feedback.textContent = `✅ Correct! ${items[itemIndex][3] || ""}`;
        feedback.className = "feedback correct";
        addScore(button.dataset.id);
      } else {
        feedback.textContent = `❌ Try again. Model: ${button.dataset.answer}`;
        feedback.className = "feedback incorrect";
      }
    });
  });
}

function renderSort() {
  const container = $("#sortTimeBox");
  container.innerHTML = DATA.sortQuiz.map((item, index) => `
    <div class="quiz-item">
      <p><strong>${escapeHtml(item[1])}</strong></p>
      <div class="options">
        <button type="button" data-answer="${item[0]}" data-choice="past" data-id="sort${index}">Past</button>
        <button type="button" data-answer="${item[0]}" data-choice="present" data-id="sort${index}">Present</button>
        <button type="button" data-answer="${item[0]}" data-choice="future" data-id="sort${index}">Future</button>
      </div>
      <div class="feedback" aria-live="polite"></div>
    </div>`).join("");

  $$("#sortTimeBox button[data-choice]").forEach((button) => {
    button.addEventListener("click", () => {
      const feedback = button.closest(".quiz-item").querySelector(".feedback");
      if (button.dataset.choice === button.dataset.answer) {
        feedback.textContent = "✅ Correct!";
        feedback.className = "feedback correct";
        addScore(button.dataset.id);
      } else {
        feedback.textContent = "❌ Try again.";
        feedback.className = "feedback incorrect";
      }
    });
  });
}

function renderNumbers() {
  $("#numbersGrid").innerHTML = DATA.numbers.map((number) => `
    <div class="mini">
      <strong>${escapeHtml(number[0])}</strong><br>
      ${escapeHtml(number[1])}<hr>
      ${escapeHtml(number[2])} — ${escapeHtml(number[3])}<br>
      <button type="button" class="speak-btn" data-speak="${escapeHtml(number[1] + ". " + number[3])}">🔊</button>
    </div>`).join("");

  const quizzes = DATA.numbers.slice(0, 12).map((number, index) => [
    `What is ${number[2]}?`,
    number[3],
    [number[1], number[3], DATA.numbers[(index + 1) % 12][3]],
    `Ordinal: ${number[2]} = ${number[3]}`
  ]);
  makeQuiz("#numberQuiz", quizzes, "num");
}

function renderQuestions() {
  $("#questionCards").innerHTML = DATA.questionCards.map((card, index) => `
    <article class="question-card">
      <h3>${escapeHtml(card[0])}</h3>
      <p>${escapeHtml(card[1])}</p>
      <p><strong>Ask me:</strong> ${escapeHtml(card[2])}</p>
      <button type="button" class="speak-btn" data-speak="${escapeHtml(card[2])}">🔊 Question</button>
      <button type="button" class="toggle-btn" data-target="qa${index}">Show model answer</button>
      <div id="qa${index}" class="model hidden">${escapeHtml(card[3])}</div>
    </article>`).join("");
}

function renderVocab() {
  const filter = $("#vocabFilter").value;
  const words = DATA.vocab.filter((word) => filter === "all" || word[0] === filter);
  $("#vocabGrid").innerHTML = words.map((word) => `
    <article class="vocab-card">
      <div class="icon">${word[1]}</div>
      <span class="tag">${escapeHtml(word[0])}</span>
      <h3>${escapeHtml(word[2])}</h3>
      <p class="fr">${escapeHtml(word[3])}</p>
      <p>${escapeHtml(word[4])}</p>
      <button type="button" class="speak-btn" data-speak="${escapeHtml(word[4])}">🔊</button>
    </article>`).join("");
  bindDynamicButtons();
}

function renderListening() {
  const listening = DATA.listenings[listeningIndex % DATA.listenings.length];
  $("#listeningTitle").textContent = listening[0];
  $("#listeningQuestion").textContent = listening[2];
  $("#listeningOptions").innerHTML = listening[3].map((option, index) => `
    <label class="quiz-item"><input type="radio" name="listen" value="${index}"> ${escapeHtml(option)}</label>`).join("");
  $("#transcript").textContent = listening[1];
  $("#listeningModel").textContent = listening[5];
  $("#transcript").classList.add("hidden");
  $("#listeningModel").classList.add("hidden");
  $("#listeningFeedback").textContent = "";
  $("#listeningFeedback").className = "feedback";
}

function renderRoleplays() {
  $("#roleplayGrid").innerHTML = DATA.roleplays.map((roleplay, index) => `
    <article class="role-card">
      <h3>${escapeHtml(roleplay[0])}</h3>
      <p><strong>Question:</strong> ${escapeHtml(roleplay[1])}</p>
      <button type="button" class="speak-btn" data-speak="${escapeHtml(roleplay[1])}">🔊 Question</button>
      <button type="button" class="toggle-btn" data-target="rp${index}">Show simple answer</button>
      <button type="button" class="toggle-btn" data-target="rpm${index}">Show model answer</button>
      <div id="rp${index}" class="model hidden">${escapeHtml(roleplay[2])}</div>
      <div id="rpm${index}" class="model hidden">${escapeHtml(roleplay[3])}<br><button type="button" class="speak-btn" data-speak="${escapeHtml(roleplay[3])}">🔊 Model</button></div>
    </article>`).join("");
}

function renderCompare() {
  $("#futureCompare").innerHTML = DATA.futureCompare.map((item) => `
    <article>
      <h3>${escapeHtml(item[0])}</h3>
      <p><strong>${escapeHtml(item[1])}</strong></p>
      <p>${escapeHtml(item[2])}</p>
      <button type="button" class="speak-btn" data-speak="${escapeHtml(item[2])}">🔊</button>
    </article>`).join("");
}

function renderWriting() {
  $("#writingGrid").innerHTML = DATA.writing.map((item, index) => `
    <article class="write-card">
      <h3>${escapeHtml(item[0])}</h3>
      <p>${escapeHtml(item[1])}</p>
      <button type="button" class="toggle-btn" data-target="w${index}">Show model</button>
      <button type="button" class="speak-btn" data-speak="${escapeHtml(item[2])}">🔊 Model</button>
      <div id="w${index}" class="model hidden">${escapeHtml(item[2]).replace(/\n/g, "<br>")}</div>
    </article>`).join("");
}

function bindDynamicButtons() {
  $$(".speak-btn").forEach((button) => {
    button.onclick = () => speak(button.dataset.speak || button.textContent);
  });
  $$(".toggle-btn").forEach((button) => {
    button.onclick = () => {
      const target = document.getElementById(button.dataset.target);
      if (target) target.classList.toggle("hidden");
    };
  });
}

function init() {
  setMax();
  renderDays();
  renderMonths();
  renderTime();
  renderSort();
  renderNumbers();
  makeQuiz("#goingToQuiz", DATA.grammarQuiz, "gt");
  renderQuestions();
  renderVocab();
  renderListening();
  renderRoleplays();
  renderCompare();
  renderWriting();
  bindDynamicButtons();

  $("#listenDays").onclick = () => speak(DATA.days.map((day) => day[0]).join(". "));
  $("#listenMonths").onclick = () => speak(DATA.months.map((month) => month[0]).join(". "));
  $("#stopSpeech").onclick = () => window.speechSynthesis.cancel();
  $("#vocabFilter").onchange = renderVocab;
  $("#newListening").onclick = () => { listeningIndex += 1; renderListening(); };
  $("#listenAudio").onclick = () => speak(DATA.listenings[listeningIndex % DATA.listenings.length][1]);
  $("#showTranscript").onclick = () => $("#transcript").classList.toggle("hidden");
  $("#showListeningModel").onclick = () => $("#listeningModel").classList.toggle("hidden");
  $("#checkListening").onclick = () => {
    const listening = DATA.listenings[listeningIndex % DATA.listenings.length];
    const chosen = $("input[name=listen]:checked");
    const feedback = $("#listeningFeedback");
    if (!chosen) {
      feedback.textContent = "Choose an answer first.";
      feedback.className = "feedback incorrect";
      return;
    }
    if (Number(chosen.value) === listening[4]) {
      feedback.textContent = "✅ Correct!";
      feedback.className = "feedback correct";
      addScore("listen" + listeningIndex);
    } else {
      feedback.textContent = "❌ Not correct. Answer: " + listening[3][listening[4]];
      feedback.className = "feedback incorrect";
    }
  };
  $$('[data-scroll]').forEach((button) => {
    button.onclick = () => document.querySelector(button.dataset.scroll).scrollIntoView({ behavior: "smooth" });
  });
}

document.addEventListener("DOMContentLoaded", init);
